2	import { PROVIDER_ENDPOINTS, ProviderEndpoint, resolveEndpointKey } from './provider-endpoints';
3	import { injectOpenRouterCacheControl } from './cache-injection';
4	import {
5	  toGoogleRequest,
6	  toAnthropicRequest,
7	  toResponsesRequest,
8	  sanitizeOpenAiBody,
9	  collectChatGptSseResponse as chatGptSseCollector,
10	  convertChatGptResponse as chatGptResponseConverter,
11	  convertChatGptStreamChunk as chatGptStreamChunkConverter,
12	  convertGoogleResponse as googleResponseConverter,
13	  convertGoogleStreamChunk as googleStreamChunkConverter,
14	  convertAnthropicResponse as anthropicResponseConverter,
15	  convertAnthropicStreamChunk as anthropicStreamChunkConverter,
16	  createAnthropicTransformer,
17	  type GoogleStreamChunkResult,
18	  type ThinkingBlocksCallback,
19	} from './provider-client-converters';
20	import { ForwardOptions } from './proxy-types';
21	
22	export interface ForwardResult {
23	  response: Response;
24	  /** True when we converted from Google format (needs SSE transform). */
25	  isGoogle: boolean;
26	  /** True when we converted from Anthropic format (needs SSE transform). */
27	  isAnthropic: boolean;
28	  /** True when we converted from ChatGPT Responses API format (needs SSE transform). */
29	  isChatGpt: boolean;
30	}
31	
32	const PROVIDER_TIMEOUT_MS = 180_000;
33	
34	/**
35	 * Strip vendor prefix from model name (e.g. "anthropic/claude-sonnet-4" → "claude-sonnet-4").
36	 * Models synced from OpenRouter use vendor prefixes, but native APIs expect bare names.
37	 */
38	function stripModelPrefix(model: string, endpointKey: string): string {
39	  // OpenRouter accepts and expects vendor prefixes
40	  if (endpointKey === 'openrouter') return model;
41	  const slashIdx = model.indexOf('/');
42	  return slashIdx > 0 ? model.substring(slashIdx + 1) : model;
43	}
44	
45	@Injectable()
46	export class ProviderClient {
47	  private readonly logger = new Logger(ProviderClient.name);
48	
49	  async forward(opts: ForwardOptions): Promise<ForwardResult> {
50	    const {
51	      provider,
52	      apiKey,
53	      model,
54	      body,
55	      stream,
56	      signal,
57	      extraHeaders,
58	      customEndpoint,
59	      authType,
60	      signatureLookup,
61	      thinkingLookup,
62	    } = opts;
63	
64	    let endpoint: ProviderEndpoint;
65	    let endpointKey: string;
66	
67	    if (customEndpoint) {
68	      endpoint = customEndpoint;
69	      endpointKey = 'custom';
70	    } else {
71	      let resolved = resolveEndpointKey(provider);
72	      if (!resolved) {
73	        throw new Error(`No endpoint configured for provider: ${provider}`);
74	      }
75	      // ChatGPT subscription tokens use a different backend endpoint
76	      if (resolved === 'openai' && authType === 'subscription') {
77	        resolved = 'openai-subscription';
78	      } else if (resolved === 'minimax' && authType === 'subscription') {
79	        resolved = 'minimax-subscription';
80	      } else if (resolved === 'zai' && authType === 'subscription') {
81	        resolved = 'zai-subscription';
82	      } else if (resolved === 'opencode-go') {
83	        // OpenCode Go uses two different API formats depending on the model:
84	        // MiniMax models use Anthropic /v1/messages, all others use OpenAI /v1/chat/completions.
85	        const slashIdx = model.indexOf('/');
86	        const bare = slashIdx > 0 ? model.substring(slashIdx + 1) : model;
87	        if (bare.toLowerCase().startsWith('minimax-')) {
88	          resolved = 'opencode-go-anthropic';
89	        }
90	      }
91	      endpointKey = resolved;
92	      endpoint = PROVIDER_ENDPOINTS[endpointKey];
93	    }
94	    const isGoogle = endpoint.format === 'google';
95	    const isAnthropic = endpoint.format === 'anthropic';
96	    const isChatGpt = endpoint.format === 'chatgpt';
97	
98	    const bareModel = stripModelPrefix(model, endpointKey);
99	    let url: string;
100	    let headers: Record<string, string>;
101	    let requestBody: Record<string, unknown>;
102	
103	    if (isGoogle) {
104	      // Google Gemini API requires the key as a URL parameter (not a header).
105	      // The key is sanitized from debug logs below but may be visible to
106	      // intermediate proxies between Manifest and Google's API.
107	      url = `${endpoint.baseUrl}${endpoint.buildPath(bareModel)}?key=${apiKey}`;
108	      if (stream) url += '&alt=sse';
109	      headers = endpoint.buildHeaders(apiKey, authType);
110	      requestBody = toGoogleRequest(body, bareModel, signatureLookup);
111	    } else if (isAnthropic) {
112	      url = `${endpoint.baseUrl}${endpoint.buildPath(bareModel)}`;
113	      headers = endpoint.buildHeaders(apiKey, authType);
114	      const isSubscription = authType === 'subscription';
115	      requestBody = toAnthropicRequest(body, bareModel, {
116	        injectCacheControl: !isSubscription,
117	        injectSubscriptionIdentity: isSubscription,
118	        thinkingLookup,
119	      });
120	      requestBody.model = bareModel;
121	      if (stream) requestBody.stream = true;
122	    } else if (isChatGpt) {
123	      url = `${endpoint.baseUrl}${endpoint.buildPath(bareModel)}`;
124	      headers = endpoint.buildHeaders(apiKey, authType);
125	      requestBody = toResponsesRequest(body, bareModel);
126	    } else {
127	      url = `${endpoint.baseUrl}${endpoint.buildPath(bareModel)}`;
128	      headers = endpoint.buildHeaders(apiKey, authType);
129	      const sanitized = sanitizeOpenAiBody(body, endpointKey, model);
130	
131	      // Inject stream_options.include_usage so providers always send token
132	      // usage in streaming responses — needed for both DB logging and
133	      // downstream clients (e.g. OpenClaw context management).
134	      if (
135	        stream &&
