26	/**
27	 * Roles excluded from scoring. Personal AI agents (OpenClaw, Hermes, and
28	 * similar tools) inject a large, keyword-rich system prompt with every
29	 * request. Scoring it inflates every request to the most expensive tier.
30	 * We strip these before the scorer sees them, but forward the full
31	 * unmodified body to the real provider.
32	 */
33	const SCORING_EXCLUDED_ROLES = new Set(['system', 'developer']);
34	const SCORING_RECENT_MESSAGES = 10;
35	
36	export interface RoutingMeta {
37	  tier: Tier;
38	  model: string;
39	  provider: string;
40	  confidence: number;
41	  reason: string;
42	  auth_type?: string;
43	  specificity_category?: string;
44	  fallbackFromModel?: string;
45	  fallbackIndex?: number;
46	  primaryErrorStatus?: number;
47	  primaryErrorBody?: string;
48	  /**
49	   * Provider of the primary model when a fallback ultimately succeeded.
50	   * Distinct from `provider`, which in a fallback-success flow holds the
51	   * fallback model's provider. Used to attribute the recorded primary
52	   * failure row to the correct vendor.
53	   */
54	  primaryProvider?: string;
55	}
56	
57	export interface ProxyResult {
58	  forward: ForwardResult;
59	  meta: RoutingMeta;
60	  failedFallbacks?: FailedFallback[];
61	}
