63	@Injectable()
64	export class ProxyService {
65	  private readonly logger = new Logger(ProxyService.name);
66	
67	  constructor(
68	    private readonly resolveService: ResolveService,
69	    private readonly providerKeyService: ProviderKeyService,
70	    private readonly tierService: TierService,
71	    private readonly openaiOauth: OpenaiOauthService,
72	    private readonly minimaxOauth: MinimaxOauthService,
73	    private readonly momentum: SessionMomentumService,
74	    private readonly limitCheck: LimitCheckService,
75	    private readonly fallbackService: ProxyFallbackService,
76	    private readonly config: ConfigService,
77	    private readonly signatureCache: ThoughtSignatureCache,
78	    private readonly thinkingCache: ThinkingBlockCache,
79	  ) {}
80	
81	  async proxyRequest(opts: ProxyRequestOptions): Promise<ProxyResult> {
82	    const { agentId, userId, body, sessionKey, tenantId, agentName, signal, specificityOverride } =
83	      opts;
84	    const messages = body.messages;
85	    if (!messages || !Array.isArray(messages) || messages.length === 0) {
86	      throw new BadRequestException('messages array is required');
87	    }
88	    sanitizeNullContent(messages as Record<string, unknown>[]);
89	
90	    // Basic payload size guard — reject absurdly large message arrays
91	    if (messages.length > 1000) {
92	      throw new BadRequestException('messages array exceeds maximum length of 1000');
93	    }
94	
95	    const limitMessage = await this.enforceLimits(tenantId, agentName);
96	    if (limitMessage) {
97	      return buildFriendlyResponse(limitMessage, body.stream === true, 'limit_exceeded');
98	    }
99	
100	    const scoringMessages = this.filterScoringMessages(messages as ScorerMessage[]);
101	    const scoringTools = Array.isArray(body.tools) ? body.tools : undefined;
102	    const isHeartbeat = this.detectHeartbeat(scoringMessages);
103	    const recentTiers = this.momentum.getRecentTiers(sessionKey);
104	
105	    const resolved = isHeartbeat
106	      ? await this.resolveService.resolveForTier(agentId, 'simple')
107	      : await this.resolveService.resolve(
108	          agentId,
109	          scoringMessages,
110	          scoringTools,
111	          body.tool_choice,
112	          body.max_tokens as number | undefined,
113	          recentTiers,
114	          specificityOverride,
115	        );
116	
117	    if (!resolved.model || !resolved.provider) {
118	      this.logger.warn(
119	        `No model available for agent=${agentId}: ` +
120	          `tier=${resolved.tier} model=${resolved.model} provider=${resolved.provider} ` +
121	          `confidence=${resolved.confidence} reason=${resolved.reason}`,
122	      );
123	      return this.buildNoProviderResult(body.stream === true, agentName);
124	    }
125	
126	    let apiKey = await this.providerKeyService.getProviderApiKey(
127	      agentId,
128	      resolved.provider,
129	      resolved.auth_type,
130	    );
131	    if (apiKey === null) {
132	      const dashboardUrl = getDashboardUrl(this.config, agentName, 'routing');
133	      const content = `[🦚 Manifest] No ${resolved.provider} API key yet. Add one here: ${dashboardUrl}`;
134	      return buildFriendlyResponse(content, body.stream === true, 'no_provider_key');
135	    }
136	
137	    const resolvedCredentials = await resolveApiKey(
138	      resolved.provider,
139	      apiKey,
140	      resolved.auth_type,
141	      agentId,
142	      userId,
143	      this.openaiOauth,
144	      this.minimaxOauth,
145	    );
146	    const providerRegion = await this.providerKeyService.getProviderRegion(
147	      agentId,
148	      resolved.provider,
149	      resolved.auth_type,
150	    );
151	    const primaryModel = normalizeProviderModel(resolved.provider, resolved.model);
152	
153	    this.logger.log(
154	      `Proxy: tier=${resolved.tier} model=${primaryModel} provider=${resolved.provider} auth_type=${resolved.auth_type} confidence=${resolved.confidence}`,
155	    );
156	
157	    const stream = body.stream === true;
158	    const signatureLookup = (toolCallId: string) =>
159	      this.signatureCache.retrieve(sessionKey, toolCallId);
160	    const thinkingLookup = (firstToolUseId: string) =>
161	      this.thinkingCache.retrieve(sessionKey, firstToolUseId);
162	    const forward = await this.fallbackService.tryForwardToProvider({
163	      provider: resolved.provider,
164	      apiKey: resolvedCredentials.apiKey,
165	      model: primaryModel,
166	      body,
167	      stream,
168	      sessionKey,
169	      signal,
170	      authType: resolved.auth_type,
171	      resourceUrl: resolvedCredentials.resourceUrl,
172	      providerRegion,
173	      signatureLookup,
174	      thinkingLookup,
175	    });
176	
177	    if (!forward.response.ok && shouldTriggerFallback(forward.response.status)) {
178	      const tiers = await this.tierService.getTiers(agentId);
179	      const assignment = tiers.find((t) => t.tier === resolved.tier);
180	      const fallbackModels = resolved.fallback_models ?? assignment?.fallback_models;
181	
182	      if (fallbackModels && fallbackModels.length > 0) {
183	        const primaryStatus = forward.response.status;
184	        const primaryErrorBody = await forward.response.text();
185	        const { success, failures } = await this.fallbackService.tryFallbacks(
186	          agentId,
187	          userId,
188	          fallbackModels,
189	          body,
190	          stream,
191	          sessionKey,
192	          primaryModel,
193	          signal,
194	          resolved.provider ?? undefined,
195	          resolved.auth_type,
196	          signatureLookup,
197	          thinkingLookup,
198	        );
199	
200	        if (success) {
201	          this.momentum.recordTier(sessionKey, resolved.tier as Tier);
202	          return {
203	            forward: success.forward,
204	            meta: {
205	              tier: resolved.tier as Tier,
206	              model: success.model,
207	              provider: success.provider,
208	              confidence: resolved.confidence,
