272	  private async enforceLimits(tenantId?: string, agentName?: string): Promise<string | null> {
273	    if (!tenantId || !agentName) return null;
274	    const exceeded = await this.limitCheck.checkLimits(tenantId, agentName);
275	    if (!exceeded) return null;
276	
277	    const fmt =
278	      exceeded.metricType === 'cost'
279	        ? `$${Number(exceeded.actual).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
280	        : Number(exceeded.actual).toLocaleString(undefined, { maximumFractionDigits: 0 });
281	    const threshFmt =
282	      exceeded.metricType === 'cost'
283	        ? `$${Number(exceeded.threshold).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
284	        : Number(exceeded.threshold).toLocaleString(undefined, { maximumFractionDigits: 0 });
285	    const dashboardUrl = getDashboardUrl(this.config, agentName, 'limits');
286	    return `[🦚 Manifest] You hit your ${exceeded.metricType} limit: ${fmt} used, ${threshFmt}/${exceeded.period} allowed. Adjust it here: ${dashboardUrl}`;
287	  }
288	
289	  private filterScoringMessages(messages: ScorerMessage[]): ScorerMessage[] {
290	    return messages
291	      .filter((m) => !SCORING_EXCLUDED_ROLES.has(m.role))
292	      .slice(-SCORING_RECENT_MESSAGES);
293	  }
294	
295	  private detectHeartbeat(scoringMessages: ScorerMessage[]): boolean {
296	    const lastUser = [...scoringMessages].reverse().find((m) => m.role === 'user');
297	    if (!lastUser) return false;
298	    if (typeof lastUser.content === 'string') return lastUser.content.includes('HEARTBEAT_OK');
299	    if (Array.isArray(lastUser.content)) {
300	      return (lastUser.content as { type?: string; text?: string }[]).some(
301	        (p) => p.type === 'text' && typeof p.text === 'string' && p.text.includes('HEARTBEAT_OK'),
302	      );
303	    }
304	    return false;
305	  }
306	
307	  private buildNoProviderResult(stream: boolean, agentName?: string): ProxyResult {
308	    const dashboardUrl = getDashboardUrl(this.config, agentName, 'routing');
309	    const content = `[🦚 Manifest] You're connected, but no providers are set up yet. Add one here: ${dashboardUrl}`;
310	    return buildFriendlyResponse(content, stream, 'no_provider');
311	  }
312	}
