1	import { Controller, Get, Param, Post } from '@nestjs/common';
2	import { CurrentUser } from '../auth/current-user.decorator';
3	import { AuthUser } from '../auth/auth.instance';
4	import { ProviderService } from './routing-core/provider.service';
5	import { ResolveAgentService } from './routing-core/resolve-agent.service';
6	import { CustomProviderService } from './custom-provider/custom-provider.service';
7	import { ModelDiscoveryService } from '../model-discovery/model-discovery.service';
8	import { OllamaSyncService } from '../database/ollama-sync.service';
9	import { PricingSyncService } from '../database/pricing-sync.service';
10	import { AgentNameParamDto } from './dto/routing.dto';
11	
12	@Controller('api/v1/routing')
13	export class ModelController {
14	  constructor(
15	    private readonly providerService: ProviderService,
16	    private readonly discoveryService: ModelDiscoveryService,
17	    private readonly ollamaSync: OllamaSyncService,
18	    private readonly resolveAgentService: ResolveAgentService,
19	    private readonly customProviderService: CustomProviderService,
20	    private readonly pricingSync: PricingSyncService,
21	  ) {}
22	
23	  @Get('pricing-health')
24	  pricingHealth() {
25	    return {
26	      model_count: this.pricingSync.getAll().size,
27	      last_fetched_at: this.pricingSync.getLastFetchedAt()?.toISOString() ?? null,
28	    };
29	  }
30	
31	  @Post('pricing/refresh')
32	  async refreshPricing() {
33	    const modelCount = await this.pricingSync.refreshCache();
34	    return {
35	      ok: modelCount > 0,
36	      model_count: modelCount,
37	      last_fetched_at: this.pricingSync.getLastFetchedAt()?.toISOString() ?? null,
38	    };
39	  }
40	
41	  @Post(':agentName/refresh-models')
42	  async refreshModels(@CurrentUser() user: AuthUser, @Param() params: AgentNameParamDto) {
43	    const agent = await this.resolveAgentService.resolve(user.id, params.agentName);
44	    await this.discoveryService.discoverAllForAgent(agent.id);
45	    await this.providerService.recalculateTiers(agent.id);
46	    return { ok: true };
47	  }
48	
49	  @Post('ollama/sync')
50	  async syncOllama() {
51	    return this.ollamaSync.sync();
52	  }
53	
54	  @Get(':agentName/available-models')
55	  async getAvailableModels(@CurrentUser() user: AuthUser, @Param() params: AgentNameParamDto) {
56	    const agent = await this.resolveAgentService.resolve(user.id, params.agentName);
57	    const models = await this.discoveryService.getModelsForAgent(agent.id);
58	
59	    // Build display name map for custom providers
60	    const customProviders = await this.customProviderService.list(agent.id);
61	    const cpNameMap = new Map<string, string>();
62	    for (const cp of customProviders) {
63	      cpNameMap.set(CustomProviderService.providerKey(cp.id), cp.name);
64	    }
65	
66	    return models.map((m) => {
67	      const isCustom = CustomProviderService.isCustom(m.provider);
68	      return {
69	        model_name: m.id,
70	        provider: m.provider,
71	        auth_type: m.authType ?? 'api_key',
72	        input_price_per_token: m.inputPricePerToken,
73	        output_price_per_token: m.outputPricePerToken,
74	        context_window: m.contextWindow,
75	        capability_reasoning: m.capabilityReasoning,
76	        capability_code: m.capabilityCode,
77	        quality_score: m.qualityScore,
78	        display_name: isCustom ? CustomProviderService.rawModelName(m.id) : m.displayName || null,
79	        ...(isCustom && {
80	          provider_display_name: cpNameMap.get(m.provider) ?? m.provider,
81	        }),
